-- ============================================================
-- Этап 10 «Инженерка» (utilities) проекта Homesteader's Cabin —
-- ФИНАЛЬНЫЙ этап карты сборки, контент из ЭТАП10_Инженерка.md.
-- Электрика, вода/канализация, отопление; честная позиция:
-- подключение к сети — только специалист с допуском и УЗО.
-- Скрипт найма электрика — в hint шага 4.
-- Идемпотентно: пересоздаёт только шаги этапа utilities (id ...320).
-- ============================================================

do $do$
begin
  if not exists (select 1 from stages
                 where id = 'de300000-0000-4000-8000-000000000320') then
    return;
  end if;

  update stages set intro = 'Финальный этап! Коробка построена, отделана — теперь вдыхаем в дом жизнь: проводим свет, воду, тепло. Щёлкнешь выключателем — загорится лампа. Откроешь кран — потечёт вода. Включишь обогрев — станет тепло. После этого дом полностью готов к жизни.

Важная честность: электрика и вода — это зоны, где ошибка опасна не «криво», а удар током, потоп, пожар. Многое ты можешь проложить сам (штробы, трубы, кабель), но финальное подключение к электросети и щитку лучше доверить электрику с допуском. Это не потому что ты не справишься с проводкой — а потому что подключение к сети требует допуска и отвечает жизнью. Тут разумнее заплатить специалисту за финал, чем рисковать.

Займёт около 5 дней (плюс работа специалиста на подключении). Когда всё заработает — поздравляю, дом готов. Ты его построил.'
  where id = 'de300000-0000-4000-8000-000000000320';

  delete from steps where stage_id = 'de300000-0000-4000-8000-000000000320';

  insert into steps (id, stage_id, sort, title, why_text, prep_text, actions, tools,
    safety_text, self_check, hint, common_mistake, helpers_needed) values
  ('de300000-0000-4000-8000-000000000511',
   'de300000-0000-4000-8000-000000000320', 1,
   'Прокладываем электропроводку',
